function HtmlPreview({ html }) {
  return (
    <div className="pivit-html-pack-root">
      <style>{`
        .pivit-html-pack-root { font-family: Pretendard Variable, Pretendard, -apple-system, BlinkMacSystemFont, system-ui, Roboto, Helvetica Neue, Segoe UI, Apple SD Gothic Neo, Noto Sans KR, Malgun Gothic, sans-serif; }
        .pivit-html-pack-root * { box-sizing: border-box; }
        .pivit-html-pack-root button, .pivit-html-pack-root input, .pivit-html-pack-root textarea, .pivit-html-pack-root select { font: inherit; }
      `}</style>
      <div style={{ lineHeight: 0 }} dangerouslySetInnerHTML={{ __html: html }} />
    </div>
  );
}

export function FullHeightHtmlPackScreen({ screenId = 'feed', stateName }) {
  const fallbackState = (SCREENS.find((screen) => screen.id === screenId)?.states || [])[0];
  const resolvedState = stateName || fallbackState;
  const html = HTML_PAGES[screenId]?.[resolvedState] || '';
  return <HtmlPreview html={html} />;
}

export default function PivitHtmlToFigmaFullHeightViewer() {
  const [activeScreen, setActiveScreen] = useState('feed');
  const [activeState, setActiveState] = useState('기본');

  const currentScreen = useMemo(() => SCREENS.find((screen) => screen.id === activeScreen) || SCREENS[0], [activeScreen]);
  const currentStates = useMemo(() => currentScreen?.states || [], [currentScreen]);
  const resolvedActiveState = currentStates.includes(activeState) ? activeState : (currentStates[0] || '');

  const groups = [
    { key: 'user', label: '사용자 화면' },
    { key: 'operator', label: '운영자 화면' },
  ];

  const html = HTML_PAGES[activeScreen]?.[resolvedActiveState] || '';

  return (
    <div style={{ fontFamily: 'Pretendard Variable, Pretendard, -apple-system, BlinkMacSystemFont, system-ui, sans-serif', display: 'grid', gap: 20, maxWidth: 980 }}>
      <div style={{ display: 'grid', gap: 12 }}>
        <div style={{ padding: '16px 18px', borderRadius: 16, border: '1px solid #F0D5DF', background: '#FFF8FB' }}>
          <div style={{ fontSize: 12, fontWeight: 800, color: '#DE0B55', marginBottom: 8 }}>화면 선택</div>
          <div style={{ display: 'grid', gap: 12 }}>
            {groups.map((group) => (
              <div key={group.key}>
                <div style={{ fontSize: 11, fontWeight: 700, color: '#8C8C8C', marginBottom: 6 }}>{group.label}</div>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                  {SCREENS.filter((screen) => screen.group === group.key).map((screen) => {
                    const selected = activeScreen === screen.id;
                    return (
                      <button
                        key={screen.id}
                        onClick={() => {
                          setActiveScreen(screen.id);
                          setActiveState(screen.states[0] || '');
                        }}
                        style={{
                          padding: '8px 14px', borderRadius: 10, border: selected ? '1.5px solid #DE0B55' : '1px solid #E0E0E0', background: selected ? 'rgba(222, 11, 85, 0.08)' : '#FFFFFF', color: selected ? '#DE0B55' : '#525252', fontSize: 13, fontWeight: selected ? 700 : 500, cursor: 'pointer'
                        }}
                      >
                        {screen.label}
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>

        <div style={{ padding: '16px 18px', borderRadius: 16, border: '1px solid #E0E0E0', background: '#FFFFFF' }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 12, marginBottom: 10, flexWrap: 'wrap' }}>
            <div>
              <div style={{ fontSize: 12, fontWeight: 800, color: '#171717', marginBottom: 4 }}>상태 선택</div>
              <div style={{ fontSize: 13, color: '#737373' }}>{currentScreen.label}</div>
            </div>
            <div style={{ display: 'inline-flex', alignItems: 'center', gap: 6, padding: '6px 10px', borderRadius: 999, background: 'rgba(222, 11, 85, 0.08)', color: '#DE0B55', fontSize: 12, fontWeight: 700 }}>
              {resolvedActiveState}
            </div>
          </div>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
            {currentStates.map((stateName) => {
              const selected = resolvedActiveState === stateName;
              return (
                <button
                  key={stateName}
                  onClick={() => setActiveState(stateName)}
                  style={{
                    padding: '7px 12px', borderRadius: 999, border: selected ? '1.5px solid #171717' : '1px solid #E0E0E0', background: selected ? '#171717' : '#FFFFFF', color: selected ? '#FFFFFF' : '#525252', fontSize: 12, fontWeight: selected ? 700 : 500, cursor: 'pointer'
                  }}
                >
                  {stateName}
                </button>
              );
            })}
          </div>
        </div>
      </div>

      <div style={{ display: 'flex', alignItems: 'flex-start', gap: 24, flexWrap: 'wrap' }}>
        <HtmlPreview html={html} />
        <div style={{ maxWidth: 360, padding: 18, borderRadius: 16, background: '#FFFFFF', border: '1px solid #E0E0E0', color: '#404040', lineHeight: 1.7 }}>
          <div style={{ fontSize: 11, fontWeight: 800, color: '#737373', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '0.06em' }}>Source</div>
          <div style={{ fontSize: 14, fontWeight: 700, color: '#171717', marginBottom: 6 }}>full-height HTML to Figma pack 기반</div>
          <div style={{ fontSize: 13, color: '#525252', marginBottom: 12 }}>이 JSX는 HTML pack 보드에 인라인으로 들어 있던 실제 DOM을 그대로 재사용해서 렌더링합니다. 즉, 이전의 &quot;대충 full-height로 바꾼 JSX&quot;가 아니라, HTML pack의 시각 결과를 기준으로 맞춘 버전입니다.</div>
          <div style={{ fontSize: 12, color: '#737373' }}>
            • 화면 구조: HTML pack 기준 그대로 유지<br/>
            • 높이: full-height(auto) 유지<br/>
            • 용도: 검토/비교/React 안에서 빠른 프리뷰
          </div>
        </div>
      </div>
    </div>
  );
}
